import React from "react"
import { MDXRenderer } from "gatsby-plugin-mdx"
import Img from "gatsby-image"
import slugify from "slugify"
import { Link } from "gatsby"
import Layout from "../../../../src/gatsby-theme-flex/layout/layout"
import Section from "../../../gatsby-theme-flex/blocks/section"

export default ({ title, excerpt, image, tags, caption, date, body }) => {
  const tagLinks = tags
    ? tags.map((tag, i) => {
      const divider = i < tags.length - 1 && <span>{`, `}</span>
      return (
        <span key={`tag-${i}`}>
          <Link
            to={`/blog/tags/${slugify(tag.toLowerCase())}`}
            className="text-dark font-bold underline dark:text-white"
          >
            {tag}
          </Link>
          {divider}
        </span>
      )
    })
    : null

  return (
    <Layout>

      <Section
        heading={title}
      >
        <div 
          style={{
                
            width: '60%',
          
        }}>
          
            <div
              sx={{
                position: 'relative', left: '50%', top: '50%',
                transform: 'translate(-50%, -50%)',

              }}
              
            >



              
              <p className="small">{date}</p>
              {excerpt && <p className="lead mt-4">{excerpt}</p>}


              {}

              <div className="lg:w-4/5 my-6 mx-auto content">
                {body && <MDXRenderer>{body}</MDXRenderer>}
              </div>

              
            </div>
          </div>




      </Section>
    </Layout>
  )
}